from flask import Flask, session, redirect, url_for, request, render_template
import requests
import urllib.parse

app = Flask(__name__)
app.secret_key = 'secret_key_here'  # set a secret key

# Authorization endpoint for your OIDC provider (e.g. Google, Okta)
AUTHORIZATION_ENDPOINT = "https://your-oidc-provider.com/oauth2/v2/auth"

@app.route("/")
def index():
    return render_template("index.html")

@app.route("/login")
def login():
    client_id = 'your_client_id_here'
    redirect_uri = url_for('callback', _external=True)  # URL for callback
    scope = "openid"
    response_type = "id_token"

    auth_url = f"{AUTHORIZATION_ENDPOINT}" \
               f"?client_id={urllib.parse.quote(client_id)}" \
               f"&redirect_uri={urllib.parse.quote(redirect_uri)}" \
               f"&scope={urllib.parse.quote(scope)}" \
               f"&response_type={urllib.parse.quote(response_type)}"

    return redirect(auth_url)

@app.route("/callback")
def callback():
    code = request.args.get("code")
    if code:
        # send the authorization code to your OIDC provider's token endpoint
        # for an access token and ID token
        token_endpoint = "https://your-oidc-provider.com/oauth2/v2/token"
        headers = {"Content-Type": "application/x-www-form-urlencoded"}
        data = {
            "grant_type": "authorization_code",
            "code": code,
            "redirect_uri": url_for('callback', _external=True),
            "client_id": 'your_client_id_here',
            "client_secret": 'your_client_secret_here'  # set your client secret
        }
        r = requests.post(token_endpoint, headers=headers, data=data)

        if r.status_code == 200:
            token_response = r.json()
            id_token = token_response.get("id_token")
            session['logged_in'] = True

            return "You are logged in!"

    return "Failed to login"

if __name__ == "__main__":
    app.run(debug=True)